  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\n// =============================\n// USER MODEL\n// =============================\nmodel User {\n  id                Int       @id @default(autoincrement())\n  firstName         String\n  lastName          String\n  username          String\n  email             String    @unique\n  password          String\n  phone             String?\n  mainBalance       Float     @default(0)\n  investmentBalance Float     @default(0)\n  totalEarn         Float     @default(0)\n  totalDeposit      Float     @default(0)\n  totalWithdrawals  Float     @default(0)\n  roi               Float     @default(0)\n  redeemedRoi       Float     @default(0)\n  speedInvest       Float     @default(0)\n  completed         Float     @default(0)\n  interestBalance   Float     @default(0)\n  rewardPoints      Float     @default(0)\n  totalReferrals    Int       @default(0)\n  referredById      Int?\n  privateKeyHash    String?\n  termsAcceptedAt   DateTime?\n  termsAcceptedIP   String?\n  createdAt         DateTime  @default(now())\n\n  // Relations\n  deposits     Deposit[]\n  investments  Investment[]\n  transactions Transaction[]\n  withdrawals  Withdrawal[]\n\n  // Referral codes created for users (Referral rows)\n  referrals Referral[] @relation(\"UserReferrals\")\n\n  // Self relation: a user can refer other users (separate relation name to avoid conflicts)\n  referredUsers User[] @relation(\"UserToUserRef\")\n  referrer      User?  @relation(\"UserToUserRef\", fields: [referredById], references: [id])\n\n  rewardLedger            RewardLedger[]\n  referralRewards         ReferralReward[] @relation(\"ReferrerRewards\")\n  referralRewardsReceived ReferralReward[] @relation(\"ReferredUserRewards\")\n  tickets                 Ticket[]\n  notifications           Notification[]\n  messages                Message[]\n  priceAlerts             PriceAlert[]\n}\n\n// =============================\n// DEPOSIT MODEL\n// =============================\nmodel Deposit {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  user      User     @relation(fields: [userId], references: [id])\n  amount    Float\n  currency  String\n  address   String\n  status    String   @default(\"Pending\") // Pending | Completed | Failed\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// =============================\n// INVESTMENT MODEL\n// =============================\nmodel Investment {\n  id           Int       @id @default(autoincrement())\n  userId       Int\n  user         User      @relation(fields: [userId], references: [id])\n  planName     String\n  planId       Int\n  roi          Float\n  duration     String\n  durationDays Int\n  amount       Float\n  startDate    DateTime  @default(now())\n  endDate      DateTime?\n  maturityDate DateTime\n  status       String    @default(\"Active\") // Active | Completed\n  createdAt    DateTime  @default(now())\n}\n\n// =============================\n// TRANSACTION MODEL\n// =============================\nmodel Transaction {\n  id             Int      @id @default(autoincrement())\n  userId         Int\n  user           User     @relation(fields: [userId], references: [id])\n  type           String? // deposit | withdraw | invest | roi\n  amount         Float\n  description    String?\n  status         String   @default(\"Success\")\n  paymentMethod  String?\n  transactionRef String?\n  createdAt      DateTime @default(now())\n}\n\n// =============================\n// WITHDRAWAL MODEL\n// =============================\nmodel Withdrawal {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  user      User     @relation(fields: [userId], references: [id])\n  amount    Float\n  address   String?\n  currency  String?\n  status    String   @default(\"Pending\")\n  createdAt DateTime @default(now())\n}\n\n// =============================\n// REFERRAL MODEL\n// =============================\nmodel Referral {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  user      User     @relation(\"UserReferrals\", fields: [userId], references: [id])\n  code      String   @unique\n  createdAt DateTime @default(now())\n}\n\n// =============================\n// REWARD LEDGER MODEL\n// =============================\nmodel RewardLedger {\n  id          Int      @id @default(autoincrement())\n  userId      Int\n  user        User     @relation(fields: [userId], references: [id])\n  type        String // 'earned' | 'redeemed'\n  points      Float\n  description String?\n  refId       Int? // Reference to deposit/investment/transaction id\n  createdAt   DateTime @default(now())\n}\n\n// =============================\n// SUPPORT TICKET MODEL\n// =============================\nmodel Ticket {\n  id        Int       @id @default(autoincrement())\n  subject   String\n  status    String    @default(\"open\")\n  userId    Int\n  user      User      @relation(fields: [userId], references: [id])\n  messages  Message[]\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n}\n\nmodel Message {\n  id        Int      @id @default(autoincrement())\n  ticketId  Int\n  ticket    Ticket   @relation(fields: [ticketId], references: [id])\n  senderId  Int\n  sender    User     @relation(fields: [senderId], references: [id])\n  content   String\n  createdAt DateTime @default(now())\n}\n\n// =============================\n// REFERRAL REWARD MODEL\n// =============================\nmodel ReferralReward {\n  id             Int       @id @default(autoincrement())\n  userId         Int // The referrer who will receive the reward\n  referredUserId Int // The user who was referred\n  amount         Float // Reward amount (e.g., $150)\n  status         String    @default(\"PENDING\") // PENDING | REDEEMED\n  createdAt      DateTime  @default(now())\n  redeemedAt     DateTime?\n\n  // Relations\n  referrer     User @relation(\"ReferrerRewards\", fields: [userId], references: [id])\n  referredUser User @relation(\"ReferredUserRewards\", fields: [referredUserId], references: [id])\n\n  @@index([userId, status])\n  @@index([referredUserId, status])\n}\n\n// =============================\n// NOTIFICATION MODEL\n// =============================\nmodel Notification {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  user      User     @relation(fields: [userId], references: [id])\n  type      String // various notification types\n  message   String\n  status    String   @default(\"info\")\n  relatedId Int?\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n}\n\n// =============================\n// PRICE ALERT MODEL\n// =============================\nmodel PriceAlert {\n  id          Int       @id @default(autoincrement())\n  userId      Int\n  user        User      @relation(fields: [userId], references: [id])\n  asset       String // BTC, ETH, etc.\n  alertType   String // TARGET | VOLATILITY\n  value       Float // Target price or volatility threshold\n  condition   String // ABOVE | BELOW (for TARGET type)\n  active      Boolean   @default(true)\n  triggeredAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  @@index([userId, active])\n  @@index([asset, active])\n}\n",
